const body = $json.body || {};

if (!body.message || typeof body.message !== 'string' || body.message.trim() === '') {
  throw new Error('Message is required');
}

return [{
  json: {
    message: body.message.trim(),
    userId: body.userId || 'anonymous',
    context: body.context || {},
    timestamp: new Date().toISOString()
  }
}];

const ctx = $json.context || {};
let contextText = '';

if (ctx.profile) contextText += `Profile: ${JSON.stringify(ctx.profile)}
`;
if (ctx.activity) contextText += `Recent Activity: ${JSON.stringify(ctx.activity)}
`;
if (ctx.nutrition) contextText += `Nutrition Log: ${JSON.stringify(ctx.nutrition)}
`;

return [{
  json: {
    ...$json,
    systemContext: contextText.trim()
  }
}];

const userMsg = $json.message;
const context = $json.systemContext || '';

const systemPrompt = `Bạn là Fitness Coach chuyên nghiệp về chạy bộ, bơi lội, phục hồi và dinh dưỡng thể thao.
Chỉ trả lời các câu hỏi liên quan đến fitness, tập luyện, dinh dưỡng và phục hồi.
Trả lời bằng tiếng Việt nếu người dùng hỏi bằng tiếng Việt.
Đưa ra lời khuyên an toàn, thực tế.`;

const fullPrompt = `${systemPrompt}

${context}

Câu hỏi: ${userMsg}`;

return [{
  json: {
    ...$json,
    systemPrompt,
    userPrompt: userMsg,
    fullPrompt
  }
}];

const response = $json;
let reply = '';

if (response.candidates?.[0]?.content?.parts?.[0]?.text) {
  reply = response.candidates[0].content.parts[0].text;
} else {
  reply = 'Xin lỗi, tôi không thể trả lời lúc này. Vui lòng thử lại sau.';
}

return [{
  json: {
    reply: reply.trim(),
    text: reply.trim(),
    success: true,
    model: $env.GEMINI_MODEL || 'gemini-2.5-flash'
  }
}];
